import{_ as e,o as r,c as i,ah as s}from"./chunks/framework.BNo2o5Ln.js";const m=JSON.parse('{"title":"Node.js","description":"","frontmatter":{"title":"Node.js","order":12},"headers":[],"relativePath":"server/nodejs/index.md","filePath":"server/nodejs/index.md"}'),l={name:"server/nodejs/index.md"};function h(d,a,n,o,t,c){return r(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="node-js" tabindex="-1">Node.js <a class="header-anchor" href="#node-js" aria-label="Permalink to “Node.js”">​</a></h1><p>Node.js 是基于 V8 引擎的 JavaScript 运行时，专为服务端高并发 I/O 设计。Node.js 的事件驱动、非阻塞 I/O 模型，使其适合 I/O 密集型应用。</p><h2 id="事件循环" tabindex="-1">事件循环 <a class="header-anchor" href="#事件循环" aria-label="Permalink to “事件循环”">​</a></h2><h3 id="事件循环的原理" tabindex="-1">事件循环的原理 <a class="header-anchor" href="#事件循环的原理" aria-label="Permalink to “事件循环的原理”">​</a></h3><p>Node.js 是单线程的，所有 JavaScript 代码在主线程执行。主线程运行事件循环，不断从事件队列中取出任务执行。</p><h3 id="事件循环的阶段" tabindex="-1">事件循环的阶段 <a class="header-anchor" href="#事件循环的阶段" aria-label="Permalink to “事件循环的阶段”">​</a></h3><p>timers（定时器）、pending callbacks（I/O 回调）、idle/prepare（内部使用）、poll（I/O 回调）、check（setImmediate）、close callbacks（close 事件回调）。</p><h3 id="微任务-vs-宏任务" tabindex="-1">微任务 vs 宏任务 <a class="header-anchor" href="#微任务-vs-宏任务" aria-label="Permalink to “微任务 vs 宏任务”">​</a></h3><p>微任务在当前宏任务执行完毕后立即执行。宏任务在事件循环的下一轮执行。</p><h2 id="异步编程" tabindex="-1">异步编程 <a class="header-anchor" href="#异步编程" aria-label="Permalink to “异步编程”">​</a></h2><h3 id="promise" tabindex="-1">Promise <a class="header-anchor" href="#promise" aria-label="Permalink to “Promise”">​</a></h3><p>Promise 是异步操作的封装，提供链式调用。async/await 是 Promise 的语法糖。</p><h3 id="回调函数" tabindex="-1">回调函数 <a class="header-anchor" href="#回调函数" aria-label="Permalink to “回调函数”">​</a></h3><p>回调是最简单的异步编程方式，但会导致回调地狱。</p><h2 id="v8-引擎" tabindex="-1">V8 引擎 <a class="header-anchor" href="#v8-引擎" aria-label="Permalink to “V8 引擎”">​</a></h2><h3 id="v8-的架构" tabindex="-1">V8 的架构 <a class="header-anchor" href="#v8-的架构" aria-label="Permalink to “V8 的架构”">​</a></h3><p>解析器、解释器、编译器、垃圾回收器。</p><h3 id="v8-的优化" tabindex="-1">V8 的优化 <a class="header-anchor" href="#v8-的优化" aria-label="Permalink to “V8 的优化”">​</a></h3><p>JIT 编译、内联缓存、隐藏类。</p><h2 id="适合场景" tabindex="-1">适合场景 <a class="header-anchor" href="#适合场景" aria-label="Permalink to “适合场景”">​</a></h2><h3 id="适合" tabindex="-1">适合 <a class="header-anchor" href="#适合" aria-label="Permalink to “适合”">​</a></h3><p>I/O 密集型应用：API 服务、实时通信、代理服务器。</p><p>实时应用：聊天应用、协作编辑。</p><p>工具链：构建工具、脚手架、CLI 工具。</p><h3 id="不适合" tabindex="-1">不适合 <a class="header-anchor" href="#不适合" aria-label="Permalink to “不适合”">​</a></h3><p>CPU 密集型应用：图像处理、视频编码。</p><p>高并发写：数据库写、日志写入。</p>',27)])])}const b=e(l,[["render",h]]);export{m as __pageData,b as default};
